import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || ''; // Ensure this is set in your environment
const ai = new GoogleGenAI({ apiKey });

export const getAIAdvice = async (userQuery: string, context: string): Promise<string> => {
  try {
    const modelId = 'gemini-3-flash-preview'; 

    const prompt = `
      You are "Lux", an AI Course Advisor for a high-end AI Masterclass called "LuxAI Academy".

      Course Context:
      ${context}

      User Query: "${userQuery}"

      Instructions:
      1. Be concise, professional, and persuasive.
      2. Keep the tone sophisticated and futuristic.
      3. Explain why this course is the right investment based on their query.
      4. If the user asks about price, mention the value they get.
      5. Keep response under 100 words.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
    });

    return response.text || "I apologize, I am currently recalibrating my neural network. Please ask again shortly.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I am currently experiencing high traffic. Please try again later.";
  }
};

