import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || ''; // Ensure this is set in your environment
const ai = new GoogleGenAI({ apiKey });

export const getAIAdvice = async (userQuery: string, context: string): Promise<string> => {
  try {
    const modelId = 'gemini-3-flash-preview'; 

    const prompt = `
      你叫 "Lux"，是高端 AI 硕士课程 "LuxAI Academy" (LuxAI 学院) 的智能课程顾问。

      课程背景信息 (Context):
      ${context}

      用户问题 (User Query): "${userQuery}"

      指令 (Instructions):
      1. 请用**中文**回答。
      2. 保持简洁、专业且具有说服力。
      3. 语气要高端、未来感强，类似资深技术专家的口吻。
      4. 根据用户的问题，解释为什么这门课程是正确的投资。
      5. 如果用户询问价格，请强调课程带来的职业价值。
      6. 回复保持在 100 字以内。
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
    });

    return response.text || "抱歉，我的神经网络正在重新校准中，请稍后再试。";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "目前的咨询请求量过大，请稍后再试。";
  }
};

