                    <div className="lg:w-1/2 p-8 md:p-12 bg-gradient-to-br from-lux-dark to-black border-b lg:border-b-0 lg:border-r border-white/5">
                        <div className="inline-block px-3 py-1 bg-lux-accent/20 text-lux-accent text-xs font-bold uppercase tracking-wider rounded mb-6">
                        近期热销
                        </div>
                        <h2 className="text-3xl md:text-4xl font-bold mb-4">预约 Preview 席位</h2>
                        <p className="text-xl text-gray-300 mb-8">
                        名额有限，先到先得<br/>
                        <span className="text-white font-bold">立即填写资料保留名额！</span>
                        </p>

                        <div className="space-y-6 mb-10">
                        <div className="flex items-start gap-4 p-4 bg-white/5 rounded-xl border border-white/10">
                            <div className="bg-lux-accent/20 p-2 rounded text-lux-accent">
                            <Ticket />
                            </div>
                            <div>
                            <h4 className="font-bold text-white">RM68 / RM100 体验课</h4>
                            <p className="text-sm text-gray-400">线下短场，快速掌握核心框架</p>
                            </div>
                        </div>

                        {/* Gift section removed as requested */}
                        </div>

                        <p className="text-xs text-gray-500 mt-auto">
                        * 您的资料将严格保密，仅用于课程通知。
                        </p>
                    </div>

                    {/* Right Side: Form */}
                    <div className="lg:w-1/2 p-8 md:p-12 flex flex-col justify-center bg-black/20">
                        <form onSubmit={handleSubmit} className="space-y-5">
                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">姓名 (Name) *</label>
                            <input 
                            required
                            type="text" 
                            value={formState.name}
                            onChange={e => setFormState({...formState, name: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-3 text-white focus:border-lux-accent focus:ring-1 focus:ring-lux-accent outline-none transition-all disabled:opacity-50"
                            placeholder="请输入您的姓名"
                            disabled={isSubmitting}
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">WhatsApp 号码 *</label>
                            <input 
                            required
                            type="tel" 
                            value={formState.phone}
                            onChange={e => setFormState({...formState, phone: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-3 text-white focus:border-lux-accent focus:ring-1 focus:ring-lux-accent outline-none transition-all disabled:opacity-50"
                            placeholder="e.g. 012-345 6789"
                            disabled={isSubmitting}
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">电子邮箱 (Email) *</label>
                            <input 
                            required
                            type="email" 
                            value={formState.email}
                            onChange={e => setFormState({...formState, email: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-3 text-white focus:border-lux-accent focus:ring-1 focus:ring-lux-accent outline-none transition-all disabled:opacity-50"
                            placeholder="example@email.com"
                            disabled={isSubmitting}
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">工作职业 (Position)</label>
                            <input 
                            type="text" 
                            value={formState.position}
                            onChange={e => setFormState({...formState, position: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-3 text-white focus:border-lux-accent focus:ring-1 focus:ring-lux-accent outline-none transition-all disabled:opacity-50"
                            placeholder="e.g. 老板 / 市场经理"
                            disabled={isSubmitting}
                            />
                        </div>

                        {error && <p className="text-red-400 text-sm">{error}</p>}

                        <button 
                            type="submit" 
                            disabled={isSubmitting}
                            className="w-full bg-lux-accent hover:bg-white text-black font-bold py-4 rounded-lg text-lg tracking-wide transition-all duration-300 mt-4 shadow-[0_0_20px_rgba(0,220,130,0.3)] hover:shadow-[0_0_30px_rgba(0,220,130,0.5)] transform hover:-translate-y-1 disabled:opacity-70 disabled:hover:translate-y-0 disabled:hover:shadow-none flex items-center justify-center gap-2"
                        >
                            {isSubmitting ? (
                            <>
                                <Loader2 className="w-5 h-5 animate-spin" />
                                提交中...
                            </>
                            ) : (
                            "提交报名咨询"
                            )}
                        </button>
                        </form>
                    </div>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, X, Send, Bot, User } from 'lucide-react';
import { getAIAdvice } from '../services/geminiService';
import { ChatMessage } from '../types';

const COURSE_CONTEXT = `
  活动名称: 《 AI 营销全流程 》线下 Preview 体验课
  讲师: Lux Lim (AI营销实战讲师)
  地点: 线下实战短场 (具体地点报名后通知)
  费用: RM68 / RM100 (不同场次)
  核心内容: 
  1. 市场调研 (把危机变商机)
  2. 内容自动化 (1人抵5人)
  3. 自动成交 (24小时线上门店)
  痛点解决: 生意累、缺人缺钱、广告没效果。
  适合对象: 第一次接触 AI 行销，想快速理解整体框架与实际应用方向的企业主。
`;

export const AIAdvisor: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "你好！我是 LuxAI 智能助手。关于 AI 营销 Preview 体验课或实战课，有什么我可以帮你的吗？", timestamp: Date.now() }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const advice = await getAIAdvice(userMsg.text, COURSE_CONTEXT);

    setMessages(prev => [...prev, { role: 'model', text: advice, timestamp: Date.now() }]);
    setIsLoading(false);
  };

  return (
    <>
      {/* Floating Button */}
      {!isOpen && (
        <button 
          onClick={() => setIsOpen(true)}
          className="fixed bottom-6 right-6 z-50 flex items-center gap-3 bg-lux-accent text-black px-5 py-3 rounded-full font-bold shadow-[0_0_20px_rgba(0,220,130,0.4)] hover:scale-105 transition-transform animate-pulse-slow"
        >
          <Bot size={20} />
          <span>咨询详情</span>
        </button>
      )}

      {/* Chat Modal */}
      {isOpen && (
        <div className="fixed bottom-6 right-6 w-[90vw] md:w-[400px] h-[500px] z-50 glass-panel rounded-2xl flex flex-col shadow-2xl border border-lux-accent/20 animate-in slide-in-from-bottom-10 fade-in duration-300">

          {/* Header */}
          <div className="p-4 border-b border-white/10 flex justify-between items-center bg-black/40 rounded-t-2xl">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-lux-accent animate-pulse"></div>
              <span className="font-bold text-white text-sm tracking-wide">AI 营销顾问</span>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-white">
              <X size={18} />
            </button>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                {msg.role === 'model' && (
                  <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center flex-shrink-0 border border-white/5">
                    <Bot size={14} className="text-lux-accent" />
                  </div>
                )}

                <div className={`max-w-[80%] p-3 text-sm leading-relaxed rounded-lg ${
                  msg.role === 'user' 
                    ? 'bg-white text-black font-medium' 
                    : 'bg-white/5 text-gray-200 border border-white/10'
                }`}>
                  {msg.text}
                </div>

                {msg.role === 'user' && (
                   <div className="w-8 h-8 rounded-full bg-lux-accent flex items-center justify-center flex-shrink-0">
                     <User size={14} className="text-black" />
                   </div>
                )}
              </div>
            ))}
            {isLoading && (
               <div className="flex gap-3 justify-start">
                  <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center border border-white/5">
                    <Bot size={14} className="text-lux-accent" />
                  </div>
                  <div className="bg-white/5 p-3 rounded-lg flex gap-1 items-center">
                    <span className="w-1.5 h-1.5 bg-gray-500 rounded-full animate-bounce"></span>
                    <span className="w-1.5 h-1.5 bg-gray-500 rounded-full animate-bounce delay-100"></span>
                    <span className="w-1.5 h-1.5 bg-gray-500 rounded-full animate-bounce delay-200"></span>
                  </div>
               </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <form onSubmit={handleSend} className="p-4 border-t border-white/10 bg-black/20 rounded-b-2xl">
            <div className="relative">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="问我关于课程内容的问题..."
                className="w-full bg-white/5 border border-white/10 rounded px-4 py-3 text-sm text-white focus:outline-none focus:border-lux-accent/50 pr-10"
              />
              <button 
                type="submit" 
                disabled={isLoading}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-lux-accent hover:text-white disabled:opacity-50 transition-colors"
              >
                <Send size={16} />
              </button>
            </div>
          </form>

        </div>
      )}
    </>
  );
};
